#include <iostream>
#include <vector>
#include <climits>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;

    vector<int> colMin(m, INT_MAX);

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            int x;
            cin >> x;
            if (x < colMin[j]) {
                colMin[j] = x;
            }
        }
    }

    for (int j = 0; j < m; j++) {
        if (j > 0) cout << ' ';
        cout << colMin[j];
    }
    cout << endl;

    return 0;
}
